using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics." },
        new() { Id = "ENG", Name = "English", Description = "Literature, writing, and linguistics." },
        new() { Id = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "HIST", Name = "History", Description = "Exploration of past events and civilizations." },
    ];

    private static readonly List<Course> Courses =
    [
        new() { Id = 1, CourseCode = "CS101", Title = "Introduction to Computer Science", Description = "An overview of computer science fundamentals including problem solving, algorithms, and programming basics using Python.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen holds a Ph.D. in Computer Science from MIT and has 15 years of teaching experience in introductory programming.", DepartmentId = "CS", IsFeatured = true },
        new() { Id = 2, CourseCode = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published extensively on graph algorithms.", DepartmentId = "CS" },
        new() { Id = 3, CourseCode = "CS301", Title = "Database Systems", Description = "Relational database design, SQL, transaction management, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked as a database architect at Oracle before joining academia.", DepartmentId = "CS", IsFeatured = true },
        new() { Id = 4, CourseCode = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with a focus on making calculus accessible to all students.", DepartmentId = "MATH", IsFeatured = true },
        new() { Id = 5, CourseCode = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra in machine learning.", DepartmentId = "MATH" },
        new() { Id = 6, CourseCode = "ENG101", Title = "English Composition", Description = "Fundamentals of academic writing, critical reading, and argumentation.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. Alice Rivera", InstructorBio = "Prof. Rivera is a published author and writing coach with 20 years of experience.", DepartmentId = "ENG" },
        new() { Id = 7, CourseCode = "ENG205", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown specializes in 20th-century American fiction and poetry.", DepartmentId = "ENG", IsFeatured = true },
        new() { Id = 8, CourseCode = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves with calculus-based problem solving.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Anil Gupta", InstructorBio = "Dr. Gupta is a former NASA researcher specializing in astrophysics and mechanics.", DepartmentId = "PHYS" },
        new() { Id = 9, CourseCode = "PHYS202", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Lisa Nakamura", InstructorBio = "Dr. Nakamura's research focuses on quantum electrodynamics and photonics.", DepartmentId = "PHYS" },
        new() { Id = 10, CourseCode = "HIST101", Title = "World History to 1500", Description = "Major civilizations, cultural developments, and events from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 4:00–5:20 PM", InstructorName = "Dr. David Okafor", InstructorBio = "Dr. Okafor is an expert in ancient civilizations and comparative world history.", DepartmentId = "HIST" },
    ];

    public List<Department> GetDepartments() => Departments;

    public Department? GetDepartment(string id) => Departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? departmentId = null, string? search = null)
    {
        var query = Courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            query = query.Where(c => c.DepartmentId.Equals(departmentId, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            query = query.Where(c =>
                c.Title.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(search, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(search, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => Courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => Courses.Where(c => c.IsFeatured).ToList();
}

