@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(Model.CourseId!.Value)?.Title)</strong> has been received.</p>
        <a href="enroll" class="btn btn-primary">Submit Another Request</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.CourseCode — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();
        if (CourseId.HasValue && Model.CourseId is null)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

