@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <PageTitle>@course.CourseCode — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h2 class="mt-4">Instructor</h2>
            <p><strong>@course.InstructorName</strong></p>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Info</h5>
                    <dl>
                        <dt>Credits</dt>
                        <dd>@course.Credits</dd>
                        <dt>Schedule</dt>
                        <dd>@course.Schedule</dd>
                        <dt>Department</dt>
                        <dd>@(Catalog.GetDepartment(course.DepartmentId)?.Name ?? course.DepartmentId)</dd>
                    </dl>
                    <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

toolArgs.new_str:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.CourseCode — @course.Title</h5>
                    <p class="card-text">@course.Credits credits · @course.Schedule</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-4">Departments</h2>
<div class="list-group">
    @foreach (var dept in departments)
    {
        <a href="courses?department=@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Name</strong> — @dept.Description
        </a>
    }
</div>

@code {
    private List<Course> featuredCourses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

toolArgs.file_text:
@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-4">
        <label for="search" class="form-label">Search</label>
        <input type="text" id="search" name="search" value="@Search" class="form-control" placeholder="Course name or code..." />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select id="department" name="department" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(dept.Id == Department)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button type="submit" class="btn btn-primary">Filter</button>
        @if (!string.IsNullOrEmpty(Search) || !string.IsNullOrEmpty(Department))
        {
            <a href="courses" class="btn btn-outline-secondary ms-2">Clear</a>
        }
    </div>
</form>

@if (courses.Count == 0)
{
    <p class="text-muted">No courses match your criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentId</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public string? Department { get; set; }

    private List<Course> courses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Department, Search);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(Model.CourseId!.Value)?.Title)</strong> has been received.</p>
        <a href="enroll" class="btn btn-primary">Submit Another Request</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.CourseCode — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = [];
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();
        if (CourseId.HasValue && Model.CourseId is null)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = true;
    }
}

